def parse_csv_genotypes(csv_path: str) -> dict:
    """Parse a simple CSV with columns: gene, diplotype"""
    import csv
    results = {}
    with open(csv_path) as f:
        reader = csv.DictReader(f)
        for row in reader:
            gene = row["gene"].strip()
            diplotype = row["diplotype"].strip()
            if gene in TARGET_GENES:
                phenotype = PHENOTYPE_MAP.get(gene, {}).get(diplotype, "Unknown")
                results[gene] = {"diplotype": diplotype, "phenotype": phenotype}
    return results

